constexpr uint D = 128;
constexpr uint W = 65;
constexpr uint ELEMS_PER_THREAD = 2;

uint t_idx = thread_position_in_grid.y;
uint d_base = thread_position_in_grid.x * ELEMS_PER_THREAD;
