spec.source:
constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;

uint t_idx = thread_position_in_grid.y;
uint d_idx = thread_position_in_grid.x;
if (t_idx >= SEQ || d_idx >= D) return;

float acc = 0.0f;
for (uint j = 0; j < W; ++j) {
    uint src = (uint)neighbor_idx[t_idx * W + j];
    if (src >= SEQ) src = 0;
    acc += (float)inp[src * D + d_idx];
}
out[t_idx * D + d_idx] = (T)(acc / (float)W);

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;

uint t_idx = thread_position_in_grid.y;
uint d_idx = thread_position_in_grid.x * 4;
if (t_idx >= SEQ || d_idx >= D) return;

float4 acc = float4(0.0f);
for (uint j = 0; j < W; ++j) {
    uint src = (uint)neighbor_idx[t_idx * W + j];
    if (src >= SEQ) src = 0;
    uint base = src * D + d_idx;
    acc += float4((float)inp[base], (float)inp[base+1], (float)inp[base+2], (float)inp[base+3]);
}
float4 result = acc / (float)W;
uint out_base = t_idx * D + d_idx;
out[out_base] = (T)result.x;
out[out_base+1] = (T)result.y;
out[out_base+2] = (T)result.z;
out[out_base+3] = (T)result.w;

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;

threadgroup float shared_inp[SEQ * D];
uint tid = thread_position_in_threadgroup.x;
uint threads = 128;

// Cooperative load into shared memory
for (uint i = tid; i < SEQ * D; i += threads) {
    shared_inp[i] = (float)inp[i];
}
threadgroup_barrier(mem_flags::mem_threadgroup);

uint t_idx = thread_position_in_grid.y;
uint d_idx = thread_position_in_grid.x;
if (t_idx >= SEQ || d_idx >= D) return;

float acc = 0.0f;
for (uint j = 0; j < W; ++j) {
    uint src = (uint)neighbor_idx[t_idx * W + j];
    if (src >= SEQ) src = 0;
    acc += shared_inp[src * D + d_idx];
}
out[t_idx * D + d_idx] = (T)(acc / (float)W);

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;

uint t_idx = thread_position_in_grid.y;
uint d_idx = thread_position_in_grid.x;
if (t_idx >= SEQ || d_idx >= D) return;

float acc = 0.0f;
uint base_idx = t_idx * W;

for (uint j = 0; j < 64; j += 4) {
    uint src0 = (uint)neighbor_idx[base_idx + j];
    uint src1 = (uint)neighbor_idx[base_idx + j + 1];
    uint src2 = (uint)neighbor_idx[base_idx + j + 2];
    uint src3 = (uint)neighbor_idx[base_idx + j + 3];
    if (src0 >= SEQ) src0 = 0;
    if (src1 >= SEQ) src1 = 0;
    if (src2 >= SEQ) src2 = 0;
    if (src3 >= SEQ) src3 = 0;
    acc += (float)inp[src0 * D + d_idx];
    acc += (float)inp[src1 * D + d_idx];
    acc += (float)inp[src2 * D + d_idx];
    acc += (float)inp[src3 * D + d_idx];
}
// Handle last element (W=65)
uint src = (uint)neighbor_idx[base_idx + 64];
if (src >= SEQ) src = 0;
acc += (float)inp[src * D + d_idx];

out[t_idx * D + d_idx] = (T)(acc / (float)W);

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;

uint tid = thread_position_in_threadgroup.x;
uint d_base = threadgroup_position_in_grid.x * 128;
uint d_idx = d_base + tid;

if (d_idx >= D) return;

threadgroup uint s_neighbors[W];

for (uint t_idx = 0; t_idx < SEQ; t_idx++) {
    // Cooperative load of neighbor indices
    if (tid < W) {
        uint nb_idx = (uint)neighbor_idx[t_idx * W + tid];
        s_neighbors[tid] = (nb_idx < SEQ) ? nb_idx : 0;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float acc = 0.0f;
    for (uint j = 0; j < W; j++) {
        acc += (float)inp[s_neighbors[j] * D + d_idx];
    }

    out[t_idx * D + d_idx] = (T)(acc / (float)W);
    threadgroup_barrier(mem_flags::mem_threadgroup);
}

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;

uint t_idx = thread_position_in_grid.y;
uint d_idx = thread_position_in_grid.x;
if (t_idx >= SEQ || d_idx >= D) return;

float cache[8];
uint cached_src[8];
uint cache_valid = 0;

float acc = 0.0f;
uint base_idx = t_idx * W;

for (uint j = 0; j < W; j++) {
    uint src = (uint)neighbor_idx[base_idx + j];
    if (src >= SEQ) src = 0;

    // Check cache
    bool found = false;
    for (uint k = 0; k < cache_valid; k++) {
        if (cached_src[k] == src) {
            acc += cache[k];
            found = true;
            break;
        }
    }

    if (!found) {
        float val = (float)inp[src * D + d_idx];
        acc += val;
        if (cache_valid < 8) {
            cache[cache_valid] = val;
            cached_src[cache_valid] = src;
            cache_valid++;
        }
    }
}

out[t_idx * D + d_idx] = (T)(acc / (float)W);

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;

uint tid = thread_position_in_threadgroup.x;
uint t_idx = thread_position_in_grid.y;
uint d_idx = thread_position_in_grid.x;

if (t_idx >= SEQ || d_idx >= D) return;

threadgroup uint s_nb[W];
threadgroup float s_vals[128];

// Load and clamp neighbor indices
if (tid < W) {
    uint nb = (uint)neighbor_idx[t_idx * W + tid];
    s_nb[tid] = (nb < SEQ) ? nb : 0;
}
threadgroup_barrier(mem_flags::mem_threadgroup);

// Partial reduction: each thread processes 1-2 neighbors
float acc = 0.0f;
uint iters = (W + 127) / 128;
for (uint i = 0; i < iters; i++) {
    uint j = tid + i * 128;
    if (j < W) {
        acc += (float)inp[s_nb[j] * D + d_idx];
    }
}

s_vals[tid] = acc;
threadgroup_barrier(mem_flags::mem_threadgroup);

// Tree reduction in threadgroup memory
for (uint stride = 64; stride > 0; stride >>= 1) {
    if (tid < stride && tid + stride < 128) {
        s_vals[tid] += s_vals[tid + stride];
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
}

if (tid == 0) {
    out[t_idx * D + d_idx] = (T)(s_vals[0] / (float)W);
}

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;

uint t_idx = thread_position_in_grid.y;
uint d_idx = thread_position_in_grid.x;
if (t_idx >= SEQ || d_idx >= D) return;

uint lane_id = thread_position_in_threadgroup.x % 32;
uint base_idx = t_idx * W;

// Each SIMD lane processes ~2 neighbors (65/32 ≈ 2)
float acc = 0.0f;
uint start = lane_id * 2;
uint end = min(start + 3, W);

for (uint j = start; j < end; j++) {
    uint src = (uint)neighbor_idx[base_idx + j];
    if (src >= SEQ) src = 0;
    acc += (float)inp[src * D + d_idx];
}

// SIMD-level reduction
float total = simd_sum(acc);

// Write once per SIMD group
if (lane_id == 0) {
    out[t_idx * D + d_idx] = (T)(total / (float)W);
}

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;
constexpr uint PAD = 1;

uint t_idx = thread_position_in_grid.y;
uint d_idx = thread_position_in_grid.x;
if (t_idx >= SEQ || d_idx >= D) return;

threadgroup float s_cache[256][D + PAD];
uint tid_x = thread_position_in_threadgroup.x;
uint tid_y = thread_position_in_threadgroup.y;

// Prefetch hot input rows into padded shared memory
uint rows_per_thread = (SEQ + 255) / 256;
for (uint r = 0; r < rows_per_thread; r++) {
    uint row = tid_x + tid_y * 128 + r * 256;
    if (row < SEQ && d_idx < D) {
        s_cache[row][d_idx] = (float)inp[row * D + d_idx];
    }
}
threadgroup_barrier(mem_flags::mem_threadgroup);

float acc = 0.0f;
uint base_idx = t_idx * W;
for (uint j = 0; j < W; j++) {
    uint src = (uint)neighbor_idx[base_idx + j];
    if (src >= SEQ) src = 0;
    acc += s_cache[src][d_idx];
}

out[t_idx * D + d_idx] = (T)(acc / (float)W);

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;

uint t_idx = thread_position_in_grid.y;
uint d_idx = thread_position_in_grid.x;
if (t_idx >= SEQ || d_idx >= D) return;

uint base_idx = t_idx * W;
float acc = 0.0f;

// Prefetch first neighbor
uint src_curr = (uint)neighbor_idx[base_idx];
if (src_curr >= SEQ) src_curr = 0;
float val_curr = (float)inp[src_curr * D + d_idx];

for (uint j = 1; j < W; j++) {
    // Prefetch next while computing current
    uint src_next = (uint)neighbor_idx[base_idx + j];
    if (src_next >= SEQ) src_next = 0;
    float val_next = (float)inp[src_next * D + d_idx];

    // Accumulate current
    acc += val_curr;

    // Swap for next iteration
    val_curr = val_next;
}

// Process last prefetched value
acc += val_curr;

out[t_idx * D + d_idx] = (T)(acc / (float)W);

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;

uint tid = thread_position_in_threadgroup.x;
uint t_idx = thread_position_in_grid.y;
uint d_idx = thread_position_in_grid.x;

if (t_idx >= SEQ || d_idx >= D) return;

threadgroup atomic_uint work_counter;
threadgroup uint s_neighbors[W];
threadgroup float s_partial[128];

if (tid == 0) {
    atomic_store_explicit(&work_counter, 0, memory_order_relaxed);
}

// Load neighbors cooperatively
if (tid < W) {
    uint nb = (uint)neighbor_idx[t_idx * W + tid];
    s_neighbors[tid] = (nb < SEQ) ? nb : 0;
}
threadgroup_barrier(mem_flags::mem_threadgroup);

// Work-stealing loop
float acc = 0.0f;
while (true) {
    uint j = atomic_fetch_add_explicit(&work_counter, 1, memory_order_relaxed);
    if (j >= W) break;
    acc += (float)inp[s_neighbors[j] * D + d_idx];
}

s_partial[tid] = acc;
threadgroup_barrier(mem_flags::mem_threadgroup);

// Reduction
if (tid == 0) {
    float total = 0.0f;
    for (uint i = 0; i < 128; i++) {
        total += s_partial[i];
    }
    out[t_idx * D + d_idx] = (T)(total / (float)W);
}

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;

uint t_idx = thread_position_in_grid.y;
uint d_idx = thread_position_in_grid.x;
if (t_idx >= SEQ || d_idx >= D) return;

float acc0 = 0.0f, acc1 = 0.0f, acc2 = 0.0f, acc3 = 0.0f;
uint base_idx = t_idx * W;

// Process in groups of 4 with independent accumulators
for (uint j = 0; j < 64; j += 4) {
    uint src0 = (uint)neighbor_idx[base_idx + j];
    uint src1 = (uint)neighbor_idx[base_idx + j + 1];
    uint src2 = (uint)neighbor_idx[base_idx + j + 2];
    uint src3 = (uint)neighbor_idx[base_idx + j + 3];

    if (src0 >= SEQ) src0 = 0;
    if (src1 >= SEQ) src1 = 0;
    if (src2 >= SEQ) src2 = 0;
    if (src3 >= SEQ) src3 = 0;

    float v0 = (float)inp[src0 * D + d_idx];
    float v1 = (float)inp[src1 * D + d_idx];
    float v2 = (float)inp[src2 * D + d_idx];
    float v3 = (float)inp[src3 * D + d_idx];

    // Independent accumulation chains
    acc0 += v0;
    acc1 += v1;
    acc2 += v2;
    acc3 += v3;
}

// Last element
uint src = (uint)neighbor_idx[base_idx + 64];
if (src >= SEQ) src = 0;
acc0 += (float)inp[src * D + d_idx];

// Combine accumulators
float total = (acc0 + acc1) + (acc2 + acc3);
out[t_idx * D + d_idx] = (T)(total / (float)W);

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;
constexpr uint ELEMS_PER_THREAD = 2;

uint t_idx = thread_position_in_grid.y;
uint d_base = thread_position_in_grid.x * ELEMS_PER_THREAD;
if (t_idx >= SEQ || d_base >= D) return;

float acc0 = 0.0f, acc1 = 0.0f;
for (uint j = 0; j < W; ++j) {
    uint src = (uint)neighbor_idx[t_idx * W + j];
    if (src >= SEQ) src = 0;
    uint offset = src * D + d_base;
    acc0 += (float)inp[offset];
    if (d_base + 1 < D) acc1 += (float)inp[offset + 1];
}
out[t_idx * D + d_base] = (T)(acc0 / (float)W);
if (d_base + 1 < D) out[t_idx * D + d_base + 1] = (T)(acc1 / (float)W);

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;
constexpr uint ELEMS_PER_THREAD = 4;

uint t_idx = thread_position_in_grid.y;
uint d_base = thread_position_in_grid.x * ELEMS_PER_THREAD;
if (t_idx >= SEQ || d_base >= D) return;

float acc0 = 0.0f, acc1 = 0.0f, acc2 = 0.0f, acc3 = 0.0f;
for (uint j = 0; j < W; ++j) {
    uint src = (uint)neighbor_idx[t_idx * W + j];
    if (src >= SEQ) src = 0;
    uint offset = src * D + d_base;
    acc0 += (float)inp[offset];
    if (d_base + 1 < D) acc1 += (float)inp[offset + 1];
    if (d_base + 2 < D) acc2 += (float)inp[offset + 2];
    if (d_base + 3 < D) acc3 += (float)inp[offset + 3];
}
float inv_w = 1.0f / (float)W;
out[t_idx * D + d_base] = (T)(acc0 * inv_w);
if (d_base + 1 < D) out[t_idx * D + d_base + 1] = (T)(acc1 * inv_w);
if (d_base + 2 < D) out[t_idx * D + d_base + 2] = (T)(acc2 * inv_w);
if (d_base + 3 < D) out[t_idx * D + d_base + 3] = (T)(acc3 * inv_w);

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;

uint t_idx = thread_position_in_grid.y;
uint d_idx = thread_position_in_grid.x;
if (t_idx >= SEQ || d_idx >= D) return;

float acc = 0.0f;
uint base_neighbor = t_idx * W;
for (uint j = 0; j < W; ++j) {
    uint src = (uint)neighbor_idx[base_neighbor + j];
    src = (src >= SEQ) ? 0 : src;
    acc += (float)inp[src * D + d_idx];
}
out[t_idx * D + d_idx] = (T)(acc / (float)W);

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;
constexpr uint ELEMS_PER_THREAD = 2;

uint t_idx = thread_position_in_grid.y;
uint d_base = thread_position_in_grid.x * ELEMS_PER_THREAD;
if (t_idx >= SEQ || d_base >= D) return;

float acc0 = 0.0f, acc1 = 0.0f;
uint neighbor_base = t_idx * W;

for (uint j = 0; j < 65; j += 5) {
    for (uint k = 0; k < 5; ++k) {
        uint idx = j + k;
        if (idx >= W) break;
        uint src = (uint)neighbor_idx[neighbor_base + idx];
        if (src >= SEQ) src = 0;
        uint offset = src * D + d_base;
        acc0 += (float)inp[offset];
        if (d_base + 1 < D) acc1 += (float)inp[offset + 1];
    }
}
out[t_idx * D + d_base] = (T)(acc0 / (float)W);
if (d_base + 1 < D) out[t_idx * D + d_base + 1] = (T)(acc1 / (float)W);

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;

uint t_idx = thread_position_in_grid.y;
uint d_idx = thread_position_in_grid.x;
if (t_idx >= SEQ || d_idx >= D) return;

uint simd_lane = thread_position_in_threadgroup.x % 32;
float acc = 0.0f;
uint neighbor_base = t_idx * W;

for (uint j = 0; j < W; ++j) {
    uint src = neighbor_idx[neighbor_base + j];
    src = (src >= SEQ) ? 0 : src;
    uint src_broadcast = simd_broadcast_first(src);
    acc += (float)inp[src_broadcast * D + d_idx];
}
out[t_idx * D + d_idx] = (T)(acc / (float)W);

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;
constexpr uint ELEMS_PER_THREAD = 2;

uint t_idx = thread_position_in_grid.y;
uint d_base = thread_position_in_grid.x * ELEMS_PER_THREAD;
if (t_idx >= SEQ || d_base >= D) return;

float acc0 = 0.0f, acc1 = 0.0f;
uint neighbor_base = t_idx * W;
uint simd_lane = thread_position_in_threadgroup.x % 32;

for (uint chunk = 0; chunk < 3; ++chunk) {
    uint j_start = chunk * 32;
    uint j_end = min(j_start + 32, W);
    for (uint j = j_start; j < j_end; ++j) {
        uint src = (uint)neighbor_idx[neighbor_base + j];
        if (src >= SEQ) src = 0;
        uint offset = src * D + d_base;
        acc0 += (float)inp[offset];
        if (d_base + 1 < D) acc1 += (float)inp[offset + 1];
    }
}
out[t_idx * D + d_base] = (T)(acc0 / (float)W);
if (d_base + 1 < D) out[t_idx * D + d_base + 1] = (T)(acc1 / (float)W);

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;
constexpr uint STAGE_SIZE = 16;

threadgroup uint s_neighbors[2][STAGE_SIZE];
threadgroup float s_partial[128];

uint t_idx = thread_position_in_grid.y;
uint d_idx = thread_position_in_grid.x;
uint tid = thread_position_in_threadgroup.x;

if (t_idx >= SEQ || d_idx >= D) return;

float acc = 0.0f;
uint neighbor_base = t_idx * W;

// Prefetch first stage
if (tid < STAGE_SIZE) {
    uint idx = (uint)neighbor_idx[neighbor_base + tid];
    s_neighbors[0][tid] = (idx >= SEQ) ? 0 : idx;
}
threadgroup_barrier(mem_flags::mem_threadgroup);

for (uint stage = 0; stage < 4; ++stage) {
    uint current_buf = stage & 1;
    uint next_buf = 1 - current_buf;

    // Prefetch next stage while computing current
    if (tid < STAGE_SIZE && (stage + 1) * STAGE_SIZE < W) {
        uint j = (stage + 1) * STAGE_SIZE + tid;
        uint idx = (uint)neighbor_idx[neighbor_base + j];
        s_neighbors[next_buf][tid] = (idx >= SEQ) ? 0 : idx;
    }

    // Compute current stage
    uint stage_end = min(STAGE_SIZE, W - stage * STAGE_SIZE);
    for (uint i = 0; i < stage_end; ++i) {
        uint src = s_neighbors[current_buf][i];
        acc += (float)inp[src * D + d_idx];
    }

    threadgroup_barrier(mem_flags::mem_threadgroup);
}

// Handle remainder
for (uint j = 64; j < W; ++j) {
    uint src = (uint)neighbor_idx[neighbor_base + j];
    if (src >= SEQ) src = 0;
    acc += (float)inp[src * D + d_idx];
}

out[t_idx * D + d_idx] = (T)(acc / (float)W);

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;

uint t_idx = thread_position_in_grid.y;
uint d_idx = thread_position_in_grid.x;

if (t_idx >= SEQ || d_idx >= D) return;

float acc = 0.0f;
uint neighbor_base = t_idx * W;

// Process 4 neighbors at a time with explicit unrolling
for (uint chunk = 0; chunk < 16; ++chunk) {
    uint j_base = chunk * 4;
    if (j_base >= W) break;

    uint src0 = (uint)neighbor_idx[neighbor_base + j_base];
    uint src1 = (j_base + 1 < W) ? (uint)neighbor_idx[neighbor_base + j_base + 1] : 0;
    uint src2 = (j_base + 2 < W) ? (uint)neighbor_idx[neighbor_base + j_base + 2] : 0;
    uint src3 = (j_base + 3 < W) ? (uint)neighbor_idx[neighbor_base + j_base + 3] : 0;

    if (src0 >= SEQ) src0 = 0;
    if (src1 >= SEQ) src1 = 0;
    if (src2 >= SEQ) src2 = 0;
    if (src3 >= SEQ) src3 = 0;

    float v0 = (float)inp[src0 * D + d_idx];
    float v1 = (j_base + 1 < W) ? (float)inp[src1 * D + d_idx] : 0.0f;
    float v2 = (j_base + 2 < W) ? (float)inp[src2 * D + d_idx] : 0.0f;
    float v3 = (j_base + 3 < W) ? (float)inp[src3 * D + d_idx] : 0.0f;

    acc += v0 + v1 + v2 + v3;
}

// Handle remainder
if (W & 3) {
    uint src = (uint)neighbor_idx[neighbor_base + 64];
    if (src < SEQ) acc += (float)inp[src * D + d_idx];
}

out[t_idx * D + d_idx] = (T)(acc / (float)W);

constexpr uint SEQ = 256;
constexpr uint D = 128;
constexpr uint W = 65;
constexpr uint CACHE_SIZE = 8;

threadgroup uint s_cache_idx[CACHE_SIZE];
threadgroup float s_cache_data[CACHE_SIZE][128];

uint t_idx = thread_position_in_grid.y;
uint d_idx = thread_position_in_grid.x;
uint tid = thread_position_in_threadgroup.x;

if (t_idx >= SEQ || d_idx >= D) return;

float acc = 0.0f;
uint neighbor_base = t_idx * W;

for (uint w_iter = 0; w_iter < W; ++w_iter) {
    uint src = (uint)neighbor_idx[neighbor_base + w_iter];
    if (src >= SEQ) src = 0;

    // Check cache
    bool hit = false;
    float value = 0.0f;

