        // Update cache with LRU
        if (tid < CACHE_SIZE && d_idx < D) {
            uint evict_slot = w_iter % CACHE_SIZE;
            s_cache_idx[evict_slot] = src;
            s_cache_data[evict_slot][d_idx] = value;
        }
    }

    acc += value;
